  'Prefer': 'return=representation'
};

// --- Helper: Supabase request ---
async function sbFetch(path, options = {}) {
  const url = `${SUPABASE_URL}${path}`;
  const resp = await httpReq(url, {
    headers: { ...sbHeaders, ...(options.headers || {}) },
    method: options.method || 'GET',
    body: options.body ? JSON.stringify(options.body) : undefined
  });
  const text = await resp.text();
  if (!resp.ok) {
    throw new Error(`Supabase ${options.method || 'GET'} ${path} failed (${resp.status}): ${text}`);
  }
  return text ? JSON.parse(text) : null;
}

// --- Helper: WooCommerce API request ---
async function wooFetch(baseUrl, path, authHeader) {
  const url = `${baseUrl}${path}`;
  const resp = await httpReq(url, {
    method: 'GET',
    headers: {
      'Authorization': authHeader,
      'Content-Type': 'application/json'
    }
  });
  if (!resp.ok) {
    const errText = await resp.text();
    throw new Error(`WooCommerce API error ${resp.status}: ${errText.substring(0, 500)}`);
  }
  const totalPages = parseInt(resp.headers['x-wp-totalpages'] || '1', 10);
  const totalItems = parseInt(resp.headers['x-wp-total'] || '0', 10);
  const data = await resp.json();
  return { data, totalPages, totalItems };
}

function safeStr(val, fallback = '') {
  if (val === null || val === undefined) return fallback;
  return String(val).trim() || fallback;
}

function safeFloat(val, fallback = 0) {
  const n = parseFloat(val);
  return isNaN(n) ? fallback : n;
}

function safeInt(val, fallback = 0) {
  const n = parseInt(val, 10);
  return isNaN(n) ? fallback : n;
}

// Strip HTML tags from WooCommerce product names
function stripHtml(str) {
  if (!str) return '';
  return str.replace(/<[^>]*>/g, '').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#039;/g, "'").replace(/&nbsp;/g, ' ').trim();
}

try {
  // ========== STEP 1: Verify token ==========
  if (!token || typeof token !== 'string') {
    return [{ json: { success: false, error: 'Missing or invalid token' } }];
  }
  if (!vendor_id) {
    return [{ json: { success: false, error: 'Missing vendor_id' } }];
  }

  // Auth verification — call auth-verify endpoint
  const authResp = await httpReq('https://api.katalync.com/webhook/auth-verify', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ token })
  });
  const authData = await authResp.json();
  if (!authData.success) {
    return [{ json: { success: false, error: authData.error || 'Token invalid or expired' } }];
  }
  const userEmail = authData.email;

  // Upsert user into Supabase (auto-provision from n8n session data)
  const upsertData = await sbFetch('/users?on_conflict=email', {
    method: 'POST',
    headers: { 'Prefer': 'resolution=merge-duplicates,return=representation' },
    body: [{
      email: authData.email,
      name: authData.name || authData.email,
      password_hash: 'oauth-managed',
      role: authData.role || 'user',
      company: authData.company || null,
      lang: authData.lang || 'es',
      onboarded: authData.onboarded || false,
      subscription_status: authData.subscription_status || 'active',
      last_login_at: new Date().toISOString()
    }]
  });
  const user_id = upsertData && upsertData.length > 0 ? upsertData[0].id : null;
  if (!user_id) {
    return [{ json: { success: false, error: 'Failed to provision user' } }];
  }

  // ========== STEP 2: Fetch vendor ==========
  const vendors = await sbFetch(
    `/vendors?id=eq.${vendor_id}&user_id=eq.${user_id}&select=*`
  );
  if (!vendors || vendors.length === 0) {
    return [{ json: { success: false, error: 'Vendor not found or access denied' } }];
  }
  const vendor = vendors[0];

  // ========== STEP 3: Validate source ==========
  if (vendor.source !== 'woocommerce') {
    return [{ json: { success: false, error: `Vendor source is '${vendor.source}', expected 'woocommerce'` } }];
  }
  if (!vendor.source_url || !vendor.source_api_key || !vendor.source_api_secret) {
    return [{ json: { success: false, error: 'Vendor missing source_url, source_api_key, or source_api_secret' } }];
  }

  const wooUrl = vendor.source_url.replace(/\/+$/, '');
  const authHeader = 'Basic ' + Buffer.from(`${vendor.source_api_key}:${vendor.source_api_secret}`).toString('base64');

  // ========== STEP 4: Create sync_log ==========
  const startedAt = new Date().toISOString();
  const syncLogs = await sbFetch('/sync_logs', {
    method: 'POST',
    body: {
      vendor_id: vendor.id,
      direction: 'pull',
      total_products: 0,
      created_count: 0,
      updated_count: 0,
      error_count: 0,
      status: 'running',
      started_at: startedAt
    }
  });
  const syncLog = syncLogs[0];
  const sync_log_id = syncLog.id;

  // ========== STEP 5-7: Fetch ALL WooCommerce products (with pagination) ==========
  let allProducts = [];
  let page = 1;
  const PER_PAGE = 100;
  const MAX_PAGES = 200; // Safety limit: 200 * 100 = 20,000 products
  let totalPages = 1;

  // First request to get total pages
  const firstResp = await wooFetch(
    wooUrl,
    `/wp-json/wc/v3/products?per_page=${PER_PAGE}&page=1&status=publish`,
    authHeader
  );
  allProducts = allProducts.concat(firstResp.data);
  totalPages = Math.min(firstResp.totalPages, MAX_PAGES);

  // Fetch remaining pages
  for (page = 2; page <= totalPages; page++) {
    try {
      const resp = await wooFetch(
        wooUrl,
        `/wp-json/wc/v3/products?per_page=${PER_PAGE}&page=${page}&status=publish`,
        authHeader
      );
      if (!resp.data || resp.data.length === 0) break;
      allProducts = allProducts.concat(resp.data);
    } catch (pageErr) {
      // Log error but continue with what we have
      console.log(`Warning: Failed to fetch page ${page}: ${pageErr.message}`);
      break;
    }

    // Rate limiting: WooCommerce typically allows ~5 req/sec
    await new Promise(resolve => setTimeout(resolve, 250));
  }

  // ========== Fetch variations for variable products ==========
  const variableProducts = allProducts.filter(p => p.type === 'variable');
  const variationMap = {}; // product_id → variations[]

  for (const vp of variableProducts) {
    try {
      let varPage = 1;
      let allVariations = [];
      let hasMore = true;

      while (hasMore) {
        const varResp = await wooFetch(
          wooUrl,
          `/wp-json/wc/v3/products/${vp.id}/variations?per_page=100&page=${varPage}`,
          authHeader
        );
        if (!varResp.data || varResp.data.length === 0) {
          hasMore = false;
        } else {
          allVariations = allVariations.concat(varResp.data);
          varPage++;
          if (varPage > varResp.totalPages) hasMore = false;
        }
        await new Promise(resolve => setTimeout(resolve, 200));
      }

      variationMap[vp.id] = allVariations;
    } catch (varErr) {
      console.log(`Warning: Failed to fetch variations for product ${vp.id}: ${varErr.message}`);
      variationMap[vp.id] = [];
    }
  }

  // ========== Map products to Katalync format ==========
  const mappedProducts = [];
  const syncErrors = [];

  for (const product of allProducts) {
    try {
      if (product.type === 'variable') {
        // Map each variation as a separate product
        const variations = variationMap[product.id] || [];
        if (variations.length === 0) {
          syncErrors.push({
            sync_log_id,
            sku: safeStr(product.sku || product.id),
            field: 'variations',
            error_type: 'missing_data',
            message: `Variable product ${product.id} (${stripHtml(product.name)}) has no variations`
          });
          continue;
        }

        for (const variation of variations) {
          try {
            let sku = safeStr(variation.sku);
            if (!sku) sku = `woo-${product.id}-${variation.id}`;

            // Build variation name from attributes
            let name = stripHtml(product.name);
            if (variation.attributes && variation.attributes.length > 0) {
              const attrStr = variation.attributes
                .map(a => safeStr(a.option))
                .filter(Boolean)
                .join(' / ');
              if (attrStr) name = `${name} - ${attrStr}`;
            }

            // Find EAN in meta_data
            const eanMeta = (variation.meta_data || []).find(
              m => m.key === '_ean' || m.key === 'ean' || m.key === '_gtin' || m.key === '_barcode'
            );

            const mapped = {
              vendor_id: vendor.id,
              sku: sku,
              ean: safeStr(eanMeta?.value),
              name: name.substring(0, 500),
              brand: safeStr(
                (product.attributes || []).find(a => a.name.toLowerCase() === 'brand' || a.name.toLowerCase() === 'marca')?.options?.[0]
              ),
              category: safeStr(product.categories?.[0]?.name),
              price: safeFloat(variation.regular_price || variation.price),
              stock: safeInt(variation.stock_quantity, 0),
              image_url: safeStr(variation.image?.src || product.images?.[0]?.src),
              raw_data: {
                woo_product_id: product.id,
                woo_variation_id: variation.id,
                woo_type: 'variation',
                woo_slug: product.slug,
                woo_status: product.status,
                woo_tags: (product.tags || []).map(t => t.name),
                variation_attributes: variation.attributes,
                sale_price: variation.sale_price,
                on_sale: variation.on_sale,
                weight: variation.weight,
                dimensions: variation.dimensions,
                manage_stock: variation.manage_stock,
                stock_status: variation.stock_status,
                tax_class: variation.tax_class
              },
              sync_status: 'synced',
              last_synced_at: new Date().toISOString()
            };
            mappedProducts.push(mapped);
          } catch (varErr) {
            syncErrors.push({
              sync_log_id,
              sku: safeStr(variation.sku || `woo-${product.id}-${variation.id}`),
              field: 'variation_mapping',
              error_type: 'mapping_error',
              message: `Error mapping variation ${variation.id}: ${varErr.message}`
            });
          }
        }
      } else {
        // Simple, grouped, or external product
        let sku = safeStr(product.sku);
        if (!sku) sku = `woo-${product.id}`;

        // Find EAN in meta_data
        const eanMeta = (product.meta_data || []).find(
          m => m.key === '_ean' || m.key === 'ean' || m.key === '_gtin' || m.key === '_barcode'
        );

        // Find brand
        const brandAttr = (product.attributes || []).find(
          a => a.name.toLowerCase() === 'brand' || a.name.toLowerCase() === 'marca'
        );

        const mapped = {
          vendor_id: vendor.id,
          sku: sku,
          ean: safeStr(eanMeta?.value),
          name: stripHtml(product.name).substring(0, 500),
          brand: safeStr(brandAttr?.options?.[0]),
          category: safeStr(product.categories?.[0]?.name),
          price: safeFloat(product.regular_price || product.price),
          stock: safeInt(product.stock_quantity, 0),
          image_url: safeStr(product.images?.[0]?.src),
          raw_data: {
            woo_product_id: product.id,
            woo_type: product.type,
            woo_slug: product.slug,
            woo_status: product.status,
            woo_tags: (product.tags || []).map(t => t.name),
            sale_price: product.sale_price,
            on_sale: product.on_sale,
            weight: product.weight,
            dimensions: product.dimensions,
            manage_stock: product.manage_stock,
            stock_status: product.stock_status,
            short_description: stripHtml(product.short_description).substring(0, 500),
            tax_class: product.tax_class,
            total_sales: product.total_sales
          },
          sync_status: 'synced',
          last_synced_at: new Date().toISOString()
        };
        mappedProducts.push(mapped);
      }
    } catch (productErr) {
      syncErrors.push({
        sync_log_id,
        sku: safeStr(product.sku || product.id),
        field: 'product_mapping',
        error_type: 'mapping_error',
        message: `Error mapping product ${product.id}: ${productErr.message}`
      });
    }
  }

  // ========== STEP 8: Upsert products into vendor_products ==========
  let createdCount = 0;
  let updatedCount = 0;
  let errorCount = syncErrors.length;
  const BATCH_SIZE = 50;

  // Get existing SKUs
  const existingProducts = await sbFetch(
    `/vendor_products?vendor_id=eq.${vendor.id}&select=sku`
  );
  const existingSkus = new Set((existingProducts || []).map(p => p.sku));

  // Upsert in batches
  for (let i = 0; i < mappedProducts.length; i += BATCH_SIZE) {
    const batch = mappedProducts.slice(i, i + BATCH_SIZE);

    try {
      await sbFetch('/vendor_products', {
        method: 'POST',
        headers: {
          'Prefer': 'resolution=merge-duplicates,return=representation'
        },
        body: batch
      });

      for (const item of batch) {
        if (existingSkus.has(item.sku)) {
          updatedCount++;
        } else {
          createdCount++;
        }
      }
    } catch (upsertErr) {
      // Fallback: individual inserts
      for (const item of batch) {
        try {
          await sbFetch('/vendor_products', {
            method: 'POST',
            headers: {
              'Prefer': 'resolution=merge-duplicates,return=representation'
            },
            body: [item]
          });
          if (existingSkus.has(item.sku)) {
            updatedCount++;
          } else {
            createdCount++;
          }
        } catch (itemErr) {
          errorCount++;
          syncErrors.push({
            sync_log_id,
            sku: item.sku,
            field: 'upsert',
            error_type: 'database_error',
            message: `Upsert failed: ${itemErr.message}`.substring(0, 500)
          });
        }
      }
    }
  }

  // ========== STEP 9: Update sync_log ==========
  const completedAt = new Date().toISOString();
  await sbFetch(`/sync_logs?id=eq.${sync_log_id}`, {
    method: 'PATCH',
    body: {
      status: errorCount > 0 ? 'completed_with_errors' : 'completed',
      total_products: mappedProducts.length,
      created_count: createdCount,
      updated_count: updatedCount,
      error_count: errorCount,
      error_details: syncErrors.length > 0 ? syncErrors.slice(0, 100) : null,
      completed_at: completedAt
    }
  });

  // ========== STEP 10: Update vendor ==========
  const syncInterval = vendor.sync_interval_hours || 24;
  const nextSyncAt = new Date(Date.now() + syncInterval * 60 * 60 * 1000).toISOString();

  await sbFetch(`/vendors?id=eq.${vendor.id}`, {
    method: 'PATCH',
    body: {
      product_count: createdCount + updatedCount,
      sync_status: errorCount > 0 ? 'completed_with_errors' : 'synced',
      last_sync_at: completedAt,
      next_sync_at: nextSyncAt,
      last_sync_products_synced: createdCount + updatedCount,
      last_sync_errors: errorCount
    }
  });

  // ========== STEP 11: Insert sync_errors ==========
  if (syncErrors.length > 0) {
    for (let i = 0; i < syncErrors.length; i += BATCH_SIZE) {
      const errorBatch = syncErrors.slice(i, i + BATCH_SIZE);
      try {
        await sbFetch('/sync_errors', {
          method: 'POST',
          body: errorBatch
        });
      } catch (e) {
        console.log('Warning: Failed to log sync errors batch:', e.message);
      }
    }
  }


  // Trigger auto-convert after sync (fire-and-forget)
  if (mappedProducts && mappedProducts.length > 0) {
    httpReq('https://api.katalync.com/webhook/auto-convert', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        token: token,
        vendor_id: vendor.id,
        marketplaces: (vendor.config && vendor.config.marketplaces) || ['sprinter_es']
      }),
      timeout: 5000
    }).catch(() => {});
  }

  // ========== STEP 12: Return result ==========
  return [{
    json: {
      success: true,
      vendor_id: vendor.id,
      vendor_name: vendor.name,
      source: 'woocommerce',
      total: mappedProducts.length,
      created: createdCount,
      updated: updatedCount,
      errors: errorCount,
      pages_fetched: Math.min(page - 1, totalPages),
      woo_products: allProducts.length,
      variable_products: variableProducts.length,
      variations_fetched: Object.values(variationMap).reduce((sum, v) => sum + v.length, 0),
      sync_log_id: sync_log_id,
      duration_ms: Date.now() - new Date(startedAt).getTime()
    }
  }];

} catch (fatalError) {
  // Fatal error handler
  try {
    if (typeof sync_log_id !== 'undefined') {
      await sbFetch(`/sync_logs?id=eq.${sync_log_id}`, {
        method: 'PATCH',
        body: {
          status: 'failed',
          error_details: [{ error: fatalError.message }],
          completed_at: new Date().toISOString()
        }
      });
    }
    if (typeof vendor !== 'undefined') {
      await sbFetch(`/vendors?id=eq.${vendor.id}`, {
        method: 'PATCH',
        body: {
          sync_status: 'error'
        }
      });
    }
  } catch (e) {
    // Best effort
  }

  return [{
    json: {
      success: false,
      error: fatalError.message,
      vendor_id: body.vendor_id || null
    }
  }];
}
